import json
with open(r"D:\桌面\毕设\exam-platform\data\all_comp_q.json", "r", encoding="utf-8") as f:
    qs = json.load(f)

# 2022
qs.append({"y":2022,"c":"已知一个长度为n的整数序列A，其中有些元素出现次数超过n/2。请设计一个时间复杂度O(n)、空间复杂度O(1)的算法找出该元素(假设一定存在)。（1）给出算法的基本设计思想。（2）采用C或C++语言描述算法。（3）证明算法的正确性。","a":"（1）摩尔投票算法：遍历数组，维护候选元素candidate和计数器count。遇到相同元素count++，不同count--，count=0时更换候选。（2）int majority(int A[],int n){int c=A[0],cnt=1;for(int i=1;i<n;i++){if(cnt==0){c=A[i];cnt=1;}else if(A[i]==c)cnt++;else cnt--;}return c;}（3）证明：每次count=0表示已遍历部分可以配对消除，剩余部分中候选元素仍占多数。最终candidate必为多数元素。","ch":101,"s":10})
qs.append({"y":2022,"c":"给定一棵二叉搜索树(BST)和一个目标值k，请设计算法在BST中查找所有与k的差值不超过d的结点值。要求：（1）描述算法设计思想。（2）分析时间复杂度。","a":"（1）中序遍历BST得到有序序列，然后用双指针滑动窗口法，在有序序列中找出值在[k-d,k+d]范围内的所有元素。（2）中序遍历O(n)，双指针扫描O(n)，总时间复杂度O(n)，空间复杂度O(n)(存储中序序列)。若直接遍历BST并判断条件，时间为O(n)，但无法利用BST的有序性优化搜索范围。","ch":103,"s":10})
qs.append({"y":2022,"c":"某计算机采用虚拟存储器，虚地址为48位，物理地址为32位，页大小为8KB。TLB采用4路组相联映射，共64项。（1）TLB的组号字段占多少位？（2）虚页号和页框号各占多少位？（3）若某程序的工作集页面数量超过TLB项数，会发生什么现象？如何缓解？","a":"（1）64项/4路=16组，组号字段=4位。（2）页大小8KB=2^13B，虚页号=48-13=35位，页框号=32-13=19位。（3）发生TLB抖动(thrashing)：频繁的TLB缺失导致大量页表访问。缓解方法：增加TLB容量、使用大页(如2MB/1GB)减少映射项数、改进替换算法。","ch":203,"s":20})
qs.append({"y":2022,"c":"某系统中有3个进程P1、P2、P3共享一个文件。P1负责写入数据，P2负责处理偶数行数据，P3负责处理奇数行数据。要求：P1每写入一行后，对应的处理进程才能处理；处理完成后P1才能写入下一行。请使用信号量机制实现同步，写出伪代码并说明信号量含义。","a":"信号量：write_done=0(写完成)；even_ready=0(偶数行就绪)；odd_ready=0(奇数行就绪)；even_done=0(偶数处理完成)；odd_done=0(奇数处理完成)。P1:for(i=0;i<N;i++){write_line(i);if(i%2==0)V(even_ready);else V(odd_ready);if(i%2==0)P(even_done);else P(odd_done);}P2:while(1){P(even_ready);process_even();V(even_done);}P3:while(1){P(odd_ready);process_odd();V(odd_done);}","ch":302,"s":30})
qs.append({"y":2022,"c":"某文件系统采用混合索引分配，索引结点包含10个直接索引、1个一级间接索引、1个二级间接索引。磁盘块大小4KB，块号占4B。（1）计算最大文件大小。（2）若要读取文件中偏移量为5MB处的数据，需要访问磁盘多少次？（3）若磁盘有100万个空闲块，采用空闲表法管理空闲空间，空闲表需要占用多少空间？","a":"（1）直接：10*4KB=40KB；一级：4KB/4B=1024块到1024*4KB=4MB；二级：1024^2*4KB=4GB。总计约4GB+4MB+40KB。（2）5MB=5120KB。直接40KB不够，一级4MB=4096KB不够(5120>4136)，在二级范围内。需读二级间接块(1次)+一级间接块(1次)+数据块(1次)=3次。（3）空闲表法：每个空闲区需起始块号(4B)+块数(4B)=8B。最坏情况每个空闲块一个表项：100万*8B=8MB。最好情况(全部连续)仅8B。","ch":304,"s":30})
qs.append({"y":2022,"c":"某网络采用TCP协议，发送端初始cwnd=1MSS，ssthresh=16MSS，RTT=50ms。在传输过程中，第8个RTT时发生超时(丢失检测)。（1）画出cwnd随时间变化图(前15个RTT)。（2）第12个RTT时的cwnd是多少？（3）若第8个RTT时收到3个重复ACK而非超时，答案有何不同？","a":"（1）慢启动：RTT1:1,RTT2:2,RTT3:4,RTT4:8,RTT5:16(达ssthresh)；拥塞避免：RTT6:17,RTT7:18,RTT8:19(超时)；ssthresh=19/2=9，cwnd=1重新慢启动：RTT9:1,RTT10:2,RTT11:4,RTT12:8,RTT13:9(达ssthresh)；拥塞避免：RTT14:10,RTT15:11。（2）第12RTT时cwnd=8。（3）若3个重复ACK(快速重传)：ssthresh=19/2=9，cwnd=ssthresh+3=12(快速恢复)。RTT9:12,RTT10:13...","ch":405,"s":40})
qs.append({"y":2022,"c":"某计算机采用5段流水线(IF,ID,EX,MEM,WB)，各段1个时钟周期。有如下指令序列：I1:LD R1,0(R2);I2:ADD R3,R1,R4;I3:SUB R5,R3,R6;I4:SD R5,0(R7)。（1）指出所有数据冒险。（2）若无转发机制，需要插入多少气泡？（3）采用转发技术后，需要多少时钟周期完成？","a":"（1）I1到I2(R1,RAW)，I2到I3(R3,RAW)，I3到I4(R5,RAW)。（2）无转发：I2需等I1的WB后(插入2气泡)，I3需等I2的WB后(插入2气泡)，I4需等I3的WB后(插入2气泡)。总周期=5+4-1+2+2+2=14周期。（3）有转发：I2可从I1的MEM段转发R1(插入1气泡)；I3可从I2的EX段转发R3(无气泡)；I4可从I3的MEM段转发？SD需要R5值在EX段可用，I3的EX段结果可直接转发给I4的EX段(无气泡)。总周期=5+4-1+1=9周期。","ch":205,"s":20})

# 2023
qs.append({"y":2023,"c":"已知一个长度为n的整数数组和一个正整数k，请设计算法找出数组中第k小的元素。要求：（1）分别给出基于排序和基于快速选择的两种算法，比较其时间复杂度。（2）若数组元素分布在0~10000之间，还可以使用什么更高效的算法？","a":"（1）基于排序：排序O(nlogn)后取第k个O(1)；基于快速选择(类似快速排序的划分)：期望O(n)，最坏O(n^2)但可通过随机化改进。（2）可使用计数排序思想：开10001大小的计数数组，遍历一遍统计频率O(n)，再从前到后累加找到第k个O(范围)。总O(n+范围)=O(n+10001)=O(n)。","ch":101,"s":10})
qs.append({"y":2023,"c":"给定一个无向连通图G=(V,E)，请设计算法判断图G是否为二分图。（1）描述算法思想。（2）采用C++或Java描述算法。（3）分析时间复杂度和空间复杂度。","a":"（1）使用BFS或DFS对图进行二着色。从任意顶点开始着红色，其邻接着蓝色，邻接的邻接着红色...若在着色过程中发现相邻顶点同色，则不是二分图。（2）BFS遍历，用color数组(-1未着色,0红色,1蓝色)。略。（3）时间复杂度O(V+E)，空间复杂度O(V)(color数组+队列)。","ch":104,"s":10})
qs.append({"y":2023,"c":"某计算机的主存地址空间为4GB，按字节编址，Cache容量为64KB，块大小为64B，采用8路组相联映射，写回+写分配策略。（1）主存地址中Tag、Index、Offset各占多少位？（2）Cache共有多少组？每组多少行？（3）写出Cache命中时的访问流程。","a":"（1）主存4GB=2^32B。块大小64B=2^6，Offset=6位。Cache 64KB/64B=1024块。8路组相联到1024/8=128组，Index=7位。Tag=32-7-6=19位。（2）Cache共128组，每组8行。（3）访问流程：CPU发出物理地址；提取Index找到对应组；同时比较组内8路的Tag与地址Tag(相联比较)；若命中且有效位为1，根据Offset读取块内数据返回CPU；若缺失则启动替换流程。","ch":203,"s":20})
qs.append({"y":2023,"c":"某系统采用请求分页管理，进程分配4个页框，访问序列：1,2,3,4,2,1,5,6,2,1,2,3,7,6,3,2,1,2,3,6。（1）用OPT(最佳)置换算法计算缺页次数。（2）比较OPT、LRU、FIFO三种算法的缺页次数并分析。","a":"（1）OPT：1缺(1);2缺(1,2);3缺(1,2,3);4缺(1,2,3,4);2命中;1命中;5缺替换4-查看未来最远使用：1,2,3最早再次使用分别是...实际需详细分析。OPT缺页约8次。（2）通常OPT<=LRU<=FIFO(缺页次数)。OPT理论上最优但无法实现；LRU近似OPT但需硬件支持；FIFO最简单但性能最差且存在Belady异常。","ch":303,"s":30})
qs.append({"y":2023,"c":"有5个进程P0~P4，3类资源R1(10),R2(5),R3(7)。T0时刻：P0已(0,1,0)最(7,5,3);P1已(2,0,0)最(3,2,2);P2已(3,0,2)最(9,0,2);P3已(2,1,1)最(2,2,2);P4已(0,0,2)最(4,3,3)。（1）T0时刻系统是否安全？（2）若P2请求(0,1,0)，能否分配？（3）若P0请求(0,1,0)，能否分配？","a":"（1）Available=(3,3,2)。存在安全序列P1到P3到P0到P2到P4，安全。（2）P2请求(0,1,0)<=Need(6,0,0)？Need[2]=(6,0,0)，请求(0,1,0)中R2=1>Need[2]的R2=0，请求不合法(超过Need)。不能分配。（3）P0请求(0,1,0)<=Need(7,4,3)且<=Available(3,3,2)。试分配得Available(3,2,2)，检查安全序列：P1(1,2,2)ok到(5,2,2)；P3(0,1,1)ok到(7,3,3)；P0(7,3,3)ok到(7,4,3)...安全。可以分配。","ch":302,"s":30})
qs.append({"y":2023,"c":"某主机IP为192.168.1.100/24，默认网关192.168.1.1。该主机向IP为10.0.0.5的服务器发送HTTP请求。（1）写出该IP数据报的源IP和目的IP。（2）若该主机ARP表中没有网关MAC地址，描述地址解析过程。（3）NAT路由器将源IP转换为200.1.1.2后，服务器返回的响应如何到达该主机？","a":"（1）源IP=192.168.1.100，目的IP=10.0.0.5。（2）主机广播ARP请求(目的MAC=FF-FF-FF-FF-FF-FF)查询192.168.1.1的MAC地址；网关收到后单播ARP应答给主机；主机记录到ARP表。（3）NAT路由器维护转换表(192.168.1.100:端口X<->200.1.1.2:端口Y)。服务器返回响应到200.1.1.2:Y，路由器查表转换目的为192.168.1.100:X，从内网接口转发。","ch":404,"s":40})
qs.append({"y":2023,"c":"某磁盘有200个柱面(0~199)，当前磁头在53号柱面。请求序列：98,183,37,122,14,124,65,67。（1）用SSTF(最短寻道时间优先)算法给出服务顺序和总寻道长度。（2）用C-SCAN(循环扫描)算法(向增加方向)给出服务顺序和总寻道长度。（3）比较两种算法的优缺点。","a":"（1）SSTF：53到65(12)到67(2)到37(30)到14(23)到98(84)到122(24)到124(2)到183(59)。总寻道=12+2+30+23+84+24+2+59=236。（2）C-SCAN(向199方向)：53到65(12)到67(2)到98(31)到122(24)到124(2)到183(59)到199(16)跳到0(199)再到14(14)到37(23)。总寻道=12+2+31+24+2+59+16+199+14+23=382。（3）SSTF平均寻道短但可能饥饿；C-SCAN更公平但总寻道可能更长。","ch":305,"s":30})

# 2024
qs.append({"y":2024,"c":"设计一个数据结构，支持以下操作：insert(val)插入元素、delete(val)删除元素、getRandom()等概率随机返回一个元素。要求所有操作的平均时间复杂度为O(1)。（1）设计数据结构并说明原理。（2）实现上述三个操作。（3）分析各操作的时间复杂度。","a":"（1）使用动态数组+哈希表。数组存储元素值，哈希表存储元素值到数组下标的映射。插入：数组末尾添加，哈希表记录下标。删除：将待删元素与数组末尾交换，更新哈希表，删除末尾。随机：在数组大小范围内生成随机下标。（2）insert:检查哈希表是否存在，不存在则push_back并记录下标。delete:找到下标，与末尾swap，更新哈希表，pop_back。getRandom:生成[0,size)随机数返回数组对应元素。（3）insert/delete/getRandom均为O(1)平均时间。","ch":101,"s":10})
qs.append({"y":2024,"c":"已知一个无向带权连通图，其顶点集V={A,B,C,D,E,F}，边集及权重如下：A-B:4,A-C:2,B-C:5,B-D:10,C-E:3,D-E:4,D-F:11,E-F:1。（1）用Kruskal算法求出最小生成树，写出选边顺序。（2）用Prim算法(从A开始)求出最小生成树，写出选边顺序。（3）该最小生成树是否唯一？说明理由。","a":"（1）Kruskal排序边：E-F(1),A-C(2),C-E(3),A-B(4),D-E(4)...选边(避免环)：E-F, A-C, C-E, A-B(注意：C-E-A-B形成环时不选A-B已选)，然后D-E。MST={E-F, A-C, C-E, A-B, D-E}，权值=1+2+3+4+4=14。（2）Prim从A：选A-C(2)；从{A,C}选C-E(3)；从{A,C,E}选E-F(1)或A-B(4)，先选E-F(1)；从{A,C,E,F}选A-B(4)；从{A,B,C,E,F}选D-E(4)。边序：A-C,C-E,E-F,A-B,D-E。（3）唯一，因为所有边权值互不相同。","ch":104,"s":10})
qs.append({"y":2024,"c":"某32位计算机，主频2GHz。某程序有指令100万条，CPI为2。现将程序在改进后的计算机上运行：增加了分支预测器(分支指令占20%，原预测错误率15%，改进后5%，错误惩罚4周期)；增加L2 Cache(L1命中率90%，缺失惩罚10周期；L2命中率80%，缺失惩罚50周期)。（1）原计算机的执行时间是多少？（2）分别计算两种改进带来的加速比。（3）综合加速比是多少？","a":"（1）原执行时间=100万*2/2GHz=1ms。（2）分支预测改进：原CPI_branch_penalty=20%*15%*4=0.12；改进后=20%*5%*4=0.04。CPI从2降到2-(0.12-0.04)=1.92。加速比=2/1.92=1.042。Cache改进：原访存CPI惩罚=30%*10=3(假设30%指令访存)，CPI=2+3=5。加L2后：L1缺失10%中L2命中80%需10周期，L2缺失20%需50周期。平均惩罚=10%*(80%*10+20%*50)=10%*(8+10)=1.8。新CPI=2+1.8=3.8。加速比=5/3.8=1.316。（3）综合：原CPI=2+0.12+3=5.12，新CPI=2+0.04+1.8=3.84。加速比=5.12/3.84=1.333。","ch":205,"s":20})
qs.append({"y":2024,"c":"某操作系统采用多级反馈队列调度，共3个队列：Q1(时间片4ms,优先级最高),Q2(时间片8ms),Q3(FCFS,优先级最低)。进程进入时先放入Q1。有进程P1(运行16ms),P2(运行12ms),P3(运行8ms)同时到达。（1）画出进程调度时序图。（2）计算平均等待时间和平均周转时间。（3）分析该调度算法的优缺点。","a":"（1）Q1时间片4ms：P1(4ms)到Q2,P2(4ms)到Q2,P3(4ms)到Q2。Q2时间片8ms：P1(8ms,P1完成剩余4ms但Q2时间片用完降到Q3),P2(8ms完成),P3(4ms完成)。Q3 FCFS：P1(4ms完成)。时序：0-4:P1(Q1);4-8:P2(Q1);8-12:P3(Q1);12-20:P1(Q2);20-28:P2(Q2完成);28-32:P3(Q2完成);32-36:P1(Q3完成)。（2）等待时间：P1=32-16-0=16?实际P1运行4+8+4=16ms，完成36ms，等待=20ms。P2=28-12-0=16?实际P2运行4+8=12，等待=16ms。P3=32-8-0=24?实际P3运行4+4=8，等待=24ms。平均等待=20ms。平均周转=(36+28+32)/3=32ms。（3）优点：短作业优先、自适应；缺点：长作业可能饥饿。","ch":301,"s":30})
qs.append({"y":2024,"c":"在IPv4网络中，某路由器收到一个IP数据报，其MF=1,DF=0,Offset=200,Total Length=500,Identification=12345。紧接着收到下一个数据报，MF=0,DF=0,Offset=260,Total Length=100,Identification=12345。（1）这两个数据报是什么关系？（2）原始数据报的总长度是多少？（3）若第二个数据报丢失，接收方如何处理？","a":"（1）两个数据报是同一原始IP数据报的不同分片，Identifier相同(12345)。第一个MF=1表示后面还有分片，Offset=200*8=1600B；第二个MF=0表示最后一片，Offset=260*8=2080B。（2）第一个片数据=500-20(IP头)=480B；第二个片数据=100-20=80B。原始数据=前面片数据+(Offset差值)+最后片数据。Offset差值=2080-1600=480B(第一个片数据量)。最后片数据=80B。总原始数据负载=2080+80=2160B或1600+480+80=2160B。原始数据报总长=2160+20=2180B。（3）若第二个丢失，接收方等待超时后丢弃已接收的分片，向发送方发送ICMP超时消息。IP不提供可靠传输，由上层TCP负责重传整个数据报。","ch":404,"s":40})
qs.append({"y":2024,"c":"某文件系统的索引结点包含以下信息：文件大小、12个直接索引、1个一级间接索引、1个二级间接索引。块大小2KB，块号4B。文件A当前大小为100KB。（1）文件A占用了哪些索引项？（2）若文件A需要扩展到5MB大小，需要新增分配多少磁盘块？（3）若磁盘的空闲块采用位示图管理，磁盘共500GB，位示图占多少空间？","a":"（1）直接索引：12*2KB=24KB>100KB，所以文件A仅使用直接索引，占用100/2=50个磁盘块，通过前50个直接索引项指向。（2）扩展到5MB=5120KB。直接索引：24KB不够。一级间接：2KB/4B=512块到512*2KB=1024KB。直接+一级=24+1024=1048KB<5120KB。二级间接：512^2*2KB=512MB。5MB在二级范围。需新增块数=5120/2-50=2560-50=2510块。（3）500GB/2KB=250M个块。位示图=250M/8=31.25MB。","ch":304,"s":30})
qs.append({"y":2024,"c":"某Web服务器使用HTTP/2协议，客户端请求一个包含1个HTML文件和10个图片的网页。每个对象大小为100KB，RTT=50ms，带宽足够大。（1）若使用HTTP/1.1非流水线方式，总时间多少？（2）若使用HTTP/1.1流水线方式，总时间多少？（3）若使用HTTP/2，总时间多少？分析HTTP/2的改进。","a":"（1）HTTP/1.1非流水线：获取HTML(1RTT)，解析发现10个图片，依次请求-响应(10*1RTT)，共11RTT=550ms。（2）流水线：获取HTML(1RTT)，一次性发送10个图片请求(1RTT)，服务器按序返回(1RTT)，共3RTT=150ms。（3）HTTP/2多路复用：1个TCP连接上并发多个流。HTML请求1RTT，同时服务器可用服务器推送(push)主动推送图片。最少2RTT=100ms。HTTP/2改进：二进制帧、多路复用、头部压缩、服务器推送。","ch":405,"s":40})

# 2025
qs.append({"y":2025,"c":"给定一个长度为n的整数数组，请设计算法找出最长的连续递增子序列的长度。（1）描述算法设计思想。（2）实现该算法并分析时间复杂度。（3）若需输出该子序列本身，需要如何修改算法？","a":"（1）一次遍历：维护当前递增长度cur_len和最大长度max_len。若A[i]>A[i-1]则cur_len++；否则cur_len=1。每步更新max_len。（2）int longest(int A[],int n){if(n==0)return 0;int cur=1,max=1;for(int i=1;i<n;i++){if(A[i]>A[i-1])cur++;else cur=1;max=(cur>max)?cur:max;}return max;}时间复杂度O(n)，空间O(1)。（3）需记录max_len对应的起始和结束下标。当cur>max时更新max_len同时记录start=i-cur+1,end=i。","ch":101,"s":10})
qs.append({"y":2025,"c":"给定一个带权有向图，可能存在负权边但无负权环。请设计算法求源点到所有其他顶点的最短路径。（1）应该使用什么算法？为什么不能用Dijkstra？（2）描述算法原理和步骤。（3）分析时间复杂度，说明如何检测负权环。","a":"（1）应使用Bellman-Ford算法。Dijkstra不能处理负权边，因为其贪心策略：一旦确定最短距离就不会再更新，负权边可能使已确定距离需要修正。（2）Bellman-Ford：初始化dist[src]=0其余无穷；重复V-1轮，每轮对所有边(u,v,w)若dist[u]+w<dist[v]则更新dist[v]=dist[u]+w。V-1轮后，再检查一遍所有边，若还有更新说明存在负权环。（3）时间复杂度O(V*E)。检测负权环：V-1轮后额外一轮松弛操作仍能更新则存在负权环。","ch":104,"s":10})
qs.append({"y":2025,"c":"某计算机的主存按字节编址，虚拟地址32位，物理地址28位，页大小4KB，TLB为16路组相联共256项。Cache为直接映射64KB，块大小64B。（1）TLB中虚页号字段和组号字段各多少位？（2）Cache的Tag、Index、Offset各多少位？（3）若TLB命中率为99%，Cache命中率为95%，TLB访问1ns，Cache访问2ns，主存访问50ns，求平均内存访问时间。","a":"（1）TLB 256项/16路=16组，组号=4位。虚页号=32-12=20位。TLB中Tag=20-4=16位。（2）Cache 64KB/64B=1024块。Offset=6位(2^6=64)。Index=10位(2^10=1024)。Tag=28-10-6=12位。（3）TLB命中：访问Cache 2ns。TLB缺失：需访问页表(50ns主存)+再访问Cache(2ns)=52ns。平均地址转换=0.99*2+0.01*52=1.98+0.52=2.5ns。然后Cache访问：命中2ns，缺失到主存50ns。平均访存=0.95*2+0.05*50=1.9+2.5=4.4ns。加上地址转换=4.4+2.5=6.9ns(需考虑实际流程)。一般：平均=(地址转换时间+Cache命中时Cache时间)*命中率+(地址转换时间+缺失时主存时间)*缺失率约=6.8ns左右。","ch":203,"s":20})
qs.append({"y":2025,"c":"有三个并发进程：输入进程从输入设备读取数据放入缓冲区B1(容量M)；处理进程从B1取数据处理后放入缓冲区B2(容量N)；输出进程从B2取数据输出。请设计信号量方案实现同步。（1）定义所需信号量及初值。（2）写出三个进程的伪代码。（3）分析是否存在死锁可能。","a":"（1）empty1=M,full1=0(缓冲区B1)；empty2=N,full2=0(缓冲区B2)；mutex1=1,mutex2=1(B1,B2互斥)。（2）输入：while(1){读取;P(empty1);P(mutex1);放入B1;V(mutex1);V(full1);}处理：while(1){P(full1);P(mutex1);从B1取;V(mutex1);V(empty1);处理;P(empty2);P(mutex2);放入B2;V(mutex2);V(full2);}输出：while(1){P(full2);P(mutex2);从B2取;V(mutex2);V(empty2);输出;}（3）不存在死锁。每个进程需要的信号量获取顺序一致(先full后empty)，且每个缓冲区互斥信号量在full/empty之间操作，不会形成循环等待。","ch":302,"s":30})
qs.append({"y":2025,"c":"某请求分页系统中，进程分配3个页框，访问序列：7,0,1,2,0,3,0,4,2,3,0,3,2,1,2,0,1,7,0,1。（1）用OPT算法计算缺页次数。（2）用LRU算法计算缺页次数。（3）若页面大小从4KB增大到2MB，对该访问序列的缺页率有何影响？","a":"（1）OPT：7缺(7);0缺(7,0);1缺(7,0,1);2缺替换7(2,0,1)-未来7第18次出现;0命中;3缺替换1(2,0,3)-1第14次;0命中;4缺替换3(2,0,4)-3第10次;2命中;3缺替换4(2,0,3);0命中;3命中;2命中;1缺替换2(1,0,3)-2未出现;2缺替换3(1,0,2);0命中;1命中;7缺替换0(1,2,7)-0未出现;0缺替换2(1,7,0);1命中。总计缺页13次。（2）LRU：7缺(7);0缺(7,0);1缺(7,0,1);2缺(2,0,1)替换7;0命中;3缺(2,0,3)替换1;0命中;4缺(4,0,3)替换2;2缺(4,0,2)替换3;3缺(3,0,2)替换4;0命中;3命中;2命中;1缺(1,0,2)替换3;2命中;0命中;1命中;7缺(7,0,1)替换2;0命中;1命中。缺页12次。（3）增大页面可减少缺页率(每次调入更多数据)，但也可能增加页内碎片和I/O开销。","ch":303,"s":30})
qs.append({"y":2025,"c":"某主机连接到交换机，交换机连接到路由器，路由器通过NAT连接互联网。主机IP:192.168.1.50/24，路由器外网IP:203.0.113.5。主机访问Web服务器(IP:198.51.100.10:80)。（1）写出从主机发出的TCP SYN报文的源IP、目的IP、源端口、目的端口。（2）经过路由器NAT转换后的报文怎样变化？（3）若内网另一主机192.168.1.51也使用相同源端口访问同一服务器，NAT如何区分？","a":"（1）源IP:192.168.1.50，目的IP:198.51.100.10，源端口:随机端口(如54321)，目的端口:80。（2）路由器NAT将源IP改为203.0.113.5，源端口改为NAT表分配的外部端口(如60001)。目的IP和端口不变。NAT表中添加映射：(192.168.1.50:54321)<->(203.0.113.5:60001)。（3）NAT为第二台主机的连接分配不同的外部端口(如60002)，映射：(192.168.1.51:54321)<->(203.0.113.5:60002)。通过不同的外部端口区分不同主机的连接。这是NAPT(网络地址端口转换)。","ch":404,"s":40})
qs.append({"y":2025,"c":"某RAID系统配置为RAID5，有5块磁盘，每块1TB。条带大小为64KB。（1）该RAID5的有效存储容量是多少？（2）若一块磁盘损坏，如何恢复数据？（3）与RAID1和RAID0相比，RAID5的读写性能如何？","a":"（1）RAID5有5块盘，1块容量用于校验(分布在各盘)，有效容量=4*1TB=4TB。（2）RAID5使用奇偶校验。损坏盘的数据=同条带内其他数据盘异或运算+校验盘数据。替换新盘后，系统自动重建数据。（3）读取：RAID5读性能良好(可并行多盘读)；RAID0读写最快(无校验开销)；RAID1读快(可并行)、写需双写(与RAID5相近)。写入：RAID5写需读旧数据+旧校验+写新数据+新校验(读-改-写开销)，小写性能较差；RAID0写最快；RAID1写需写两份。综合：RAID0性能最优无冗余；RAID1读优写可接受100%冗余；RAID5是容量、性能和冗余的折中。","ch":305,"s":30})

